## 3️⃣ Manual Optimistic Updates with useState

```javascript
function QuickToggle({ item, onUpdate }) {
  const [localItem, setLocalItem] = useState(item)
  const [saving, setSaving] = useState(false)

  const toggleComplete = async () => {
    const previousItem = localItem

    // Optimistic update — instant feedback
    setLocalItem(prev => ({ ...prev, completed: !prev.completed }))

    try {
      setSaving(true)
      await api.patch(`/api/items/${item.id}`, { completed: !item.completed })
    } catch (error) {
      // ❌ Failed — revert
      setLocalItem(previousItem)
      toast.error('Failed to update. Please try again.')
    } finally {
      setSaving(false)
    }
  }

  return (
    <div>
      <input type="checkbox" checked={localItem.completed} onChange={toggleComplete} />
      {saving && <span className="saving-indicator">...</span>}
    </div>
  )
}
```

