## 4️⃣ Real-Time with WebSockets

WebSockets provide a **persistent, bidirectional connection** between client and server — ideal for chat, notifications, collaborative editing.

```bash
npm install socket.io         # Backend
npm install socket.io-client  # Frontend
```

```javascript
// Backend: Express + Socket.IO
const { Server } = require('socket.io')
const io = new Server(httpServer, {
  cors: { origin: 'http://localhost:3000' }
})

io.on('connection', (socket) => {
  console.log('User connected:', socket.id)

  socket.on('chat:message', (message) => {
    // Broadcast to ALL clients
    io.emit('chat:message', { ...message, id: socket.id })
  })

  socket.on('join:room', (roomId) => {
    socket.join(roomId)
  })

  socket.on('disconnect', () => {
    console.log('User disconnected:', socket.id)
  })
})

// Emit to specific room only
io.to(roomId).emit('room:update', data)
```

---

## 5️⃣ Socket.IO Frontend

```javascript
import { useEffect, useRef, useState } from 'react'
import { io } from 'socket.io-client'

function ChatRoom({ roomId }) {
  const [messages, setMessages] = useState([])
  const socketRef = useRef(null)

  useEffect(() => {
    // Connect to socket server
    socketRef.current = io(process.env.NEXT_PUBLIC_API_URL)
    const socket = socketRef.current

    // Join room
    socket.emit('join:room', roomId)

    // Listen for new messages
    socket.on('chat:message', (message) => {
      setMessages(prev => [...prev, message])
    })

    // Cleanup on unmount
    return () => socket.disconnect()
  }, [roomId])

  const sendMessage = (text) => {
    socketRef.current.emit('chat:message', { text, roomId })
  }

  return (
    <div>
      {messages.map(m => <p key={m.id}>{m.text}</p>)}
    </div>
  )
}
```

